export interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, Record<string, unknown>[]>;
}

function coerceValue(value: string | undefined | null): unknown {
  if (value === undefined || value === null) {
    return null;
  }
  const trimmed = value.trim();
  if (trimmed === "") {
    return null;
  }
  if (/^null$/i.test(trimmed)) {
    return null;
  }
  if (/^(true|false)$/i.test(trimmed)) {
    return /^true$/i.test(trimmed);
  }
  if (/^-?\d+(\.\d+)?$/.test(trimmed)) {
    return Number(trimmed);
  }
  return trimmed;
}

function createResult(
  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,
    filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult {
      return createResult(rows.filter(predicate), headers, errors);
    },
    sum(column: string): number {
      return rows.reduce((total, row) => {
        const value = row[column];
        if (typeof value === "number" && !Number.isNaN(value)) {
          return total + value;
        }
        return total;
      }, 0);
    },
    average(column: string): number {
      let count = 0;
      const total = rows.reduce((sum, row) => {
        const value = row[column];
        if (typeof value === "number" && !Number.isNaN(value)) {
          count += 1;
          return sum + value;
        }
        return sum;
      }, 0);
      return count === 0 ? 0 : total / count;
    },
    count(): number {
      return rows.length;
    },
    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const grouped = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        const bucket = grouped.get(key);
        if (bucket) {
          bucket.push(row);
        } else {
          grouped.set(key, [row]);
        }
      }
      return grouped;
    }
  };
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ",";
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator;

  if (!input || input.length === 0) {
    return createResult([], [], []);
  }

  const rows: string[][] = [];
  const rowNumbers: number[] = [];
  const errors: CSVError[] = [];

  let field = "";
  let row: string[] = [];
  let inQuotes = false;
  let lineNumber = 1;

  const pushRow = () => {
    rows.push(row);
    rowNumbers.push(lineNumber);
    row = [];
    lineNumber += 1;
  };

  for (let i = 0; i < input.length; i += 1) {
    const char = input[i];

    if (inQuotes) {
      if (char === quoteChar) {
        if (input[i + 1] === quoteChar) {
          field += quoteChar;
          i += 1;
        } else {
          inQuotes = false;
        }
      } else {
        field += char;
      }
      continue;
    }

    if (char === quoteChar) {
      inQuotes = true;
      continue;
    }

    if (lineSeparator) {
      if (input.startsWith(lineSeparator, i)) {
        row.push(field);
        field = "";
        pushRow();
        i += lineSeparator.length - 1;
        continue;
      }
    } else if (char === "\n" || char === "\r") {
      row.push(field);
      field = "";
      if (char === "\r" && input[i + 1] === "\n") {
        i += 1;
      }
      pushRow();
      continue;
    }

    if (char === delimiter) {
      row.push(field);
      field = "";
      continue;
    }

    field += char;
  }

  if (inQuotes) {
    errors.push({
      row: lineNumber,
      message: "Unclosed quoted field"
    });
  }

  const shouldPush = row.length > 0 || field !== "" || input.endsWith(delimiter);
  if (shouldPush) {
    row.push(field);
    pushRow();
  }

  if (rows.length === 0) {
    return createResult([], [], errors);
  }

  const headers = rows[0];
  const dataRows = rows.slice(1);
  const dataRowNumbers = rowNumbers.slice(1);
  const parsedRows: Record<string, unknown>[] = [];

  dataRows.forEach((dataRow, index) => {
    if (dataRow.length !== headers.length) {
      errors.push({
        row: dataRowNumbers[index],
        message: `Row has ${dataRow.length} fields but expected ${headers.length}`
      });
    }
    const record: Record<string, unknown> = {};
    headers.forEach((header, columnIndex) => {
      const value = dataRow[columnIndex];
      record[header] = coerceValue(value);
    });
    parsedRows.push(record);
  });

  return createResult(parsedRows, headers, errors);
}

import { parseCSV } from "./csv-parser";

function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(message);
  }
}

function assertEqual<T>(actual: T, expected: T, message: string): void {
  if (actual !== expected) {
    throw new Error(`${message} (expected: ${expected}, actual: ${actual})`);
  }
}

function assertDeepEqual(actual: unknown, expected: unknown, message: string): void {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(`${message} (expected: ${expectedJson}, actual: ${actualJson})`);
  }
}

// Basic parsing
{
  const input = "name,age\nAlice,30\nBob,25";
  const result = parseCSV(input);
  assertDeepEqual(result.headers, ["name", "age"], "Headers should parse correctly");
  assertEqual(result.rows.length, 2, "Should parse two rows");
  assertDeepEqual(result.rows[0], { name: "Alice", age: 30 }, "First row should parse");
  assertDeepEqual(result.rows[1], { name: "Bob", age: 25 }, "Second row should parse");
}

// Quoted fields with commas
{
  const input = "name,description\n\"Widget, Large\",\"A, B\"";
  const result = parseCSV(input);
  assertDeepEqual(result.rows[0], { name: "Widget, Large", description: "A, B" }, "Quoted fields should preserve commas");
}

// Escaped quotes
{
  const input = "quote\n\"He said \"\"Hello\"\"\"";
  const result = parseCSV(input);
  assertDeepEqual(result.rows[0], { quote: "He said \"Hello\"" }, "Escaped quotes should unescape");
}

// Custom delimiters
{
  const input = "name;age\nAlice;30";
  const result = parseCSV(input, { delimiter: ";" });
  assertDeepEqual(result.rows[0], { name: "Alice", age: 30 }, "Custom delimiter should parse");
}

// Type coercion
{
  const input = "int,float,boolTrue,boolFalse,nullUpper,nullLower,empty,string\n42,3.14,true,FALSE,NULL,null,,hello";
  const result = parseCSV(input);
  assertDeepEqual(
    result.rows[0],
    {
      int: 42,
      float: 3.14,
      boolTrue: true,
      boolFalse: false,
      nullUpper: null,
      nullLower: null,
      empty: null,
      string: "hello"
    },
    "Type coercion should convert values"
  );
}

// Malformed row error collection
{
  const input = "a,b\n1,2,3\n4";
  const result = parseCSV(input);
  assertEqual(result.errors.length, 2, "Should collect errors for malformed rows");
  assertEqual(result.errors[0].row, 2, "First error should reference row 2");
  assertEqual(result.errors[1].row, 3, "Second error should reference row 3");
}

// Filter functionality
{
  const input = "name,age\nAlice,30\nBob,20\nCara,40";
  const result = parseCSV(input);
  const filtered = result.filter((row) => (row.age as number) > 25);
  assertEqual(filtered.rows.length, 2, "Filter should return matching rows");
  assertEqual(filtered.rows[0].name, "Alice", "Filtered result should include Alice");
  assertEqual(filtered.rows[1].name, "Cara", "Filtered result should include Cara");
}

// Aggregation methods
{
  const input = "category,value\nA,10\nA,20\nB,30\nB,not-number";
  const result = parseCSV(input);
  assertEqual(result.count(), 4, "Count should return total rows");
  assertEqual(result.sum("value"), 60, "Sum should add numeric values");
  assertEqual(result.average("value"), 20, "Average should compute numeric values only");
  const grouped = result.groupBy("category");
  assertEqual(grouped.get("A")?.length ?? 0, 2, "GroupBy should group A values");
  assertEqual(grouped.get("B")?.length ?? 0, 2, "GroupBy should group B values");
}

// Edge cases
{
  const emptyResult = parseCSV("");
  assertEqual(emptyResult.headers.length, 0, "Empty input should have no headers");
  assertEqual(emptyResult.rows.length, 0, "Empty input should have no rows");

  const singleColumn = parseCSV("name\nAlice\nBob");
  assertEqual(singleColumn.headers.length, 1, "Single column should parse header");
  assertEqual(singleColumn.rows.length, 2, "Single column should parse rows");
  assertDeepEqual(singleColumn.rows[0], { name: "Alice" }, "Single column row should parse");

  const singleRow = parseCSV("a,b,c");
  assertEqual(singleRow.rows.length, 0, "Header-only input should have no rows");

  const largeField = "a".repeat(10000);
  const largeInput = `value\n\"${largeField}\"`;
  const largeResult = parseCSV(largeInput);
  assertEqual(largeResult.rows[0].value, largeField, "Large fields should parse correctly");
}

console.log("All CSV parser tests passed.");

